55: impl<'tcx> Index<BorrowIndex> for BorrowSet<'tcx> {
56:     type Output = BorrowData<'tcx>;
57: 
58:     fn index(&self, index: BorrowIndex) -> &BorrowData<'tcx> {
59:         &self.location_map[index.as_usize()]
60:     }
61: }
