63: /// Location where a two-phase borrow is activated, if a borrow
64: /// is in fact a two-phase borrow.
65: #[derive(Copy, Clone, PartialEq, Eq, Debug)]
66: pub enum TwoPhaseActivation {
67:     NotTwoPhase,
68:     NotActivated,
69:     ActivatedAt(Location),
70: }
